// n8n Function node - Robust JSON sanitizer + parser
// Input: items[*] - tries to locate assistant text in common places
// Output: { Hook, caption, hashtags } or error/debug info

function findTextField(obj) {
  if (!obj) return null;
  // common paths in payloads you showed
  if (typeof obj.text === 'string') return obj.text;
  if (obj.output && Array.isArray(obj.output)) {
    for (const o of obj.output) {
      if (o.content && Array.isArray(o.content)) {
        for (const c of o.content) {
          if (typeof c.text === 'string') return c.text;
        }
      }
      if (typeof o.text === 'string') return o.text;
    }
  }
  // fallback: stringified
  return JSON.stringify(obj);
}

function findJsonSubstring(s) {
  if (!s || typeof s !== 'string') return null;
  // strip obvious markdown/code fences/backticks
  s = s.replace(/```json|```/gi, '').replace(/`/g, '');
  const start = s.indexOf('{');
  if (start === -1) return null;
  let stack = 0;
  for (let i = start; i < s.length; i++) {
    const ch = s[i];
    if (ch === '{') stack++;
    else if (ch === '}') {
      stack--;
      if (stack === 0) return s.slice(start, i + 1);
    }
  }
  return null;
}

// sanitize problematic control chars and normalize punctuation
function sanitizeCandidate(raw) {
  // If the string already contains literal sequences like \\n (two chars), keep them.
  // We'll operate on the raw as-is, but convert problematic control chars to \uXXXX.
  let s = raw;

  // Replace common “smart” punctuation with ASCII equivalents
  s = s.replace(/\u2018|\u2019/g, "'"); // left/right single quote -> '
  s = s.replace(/\u201C|\u201D/g, '"'); // left/right double quote -> "
  s = s.replace(/\u2013|\u2014/g, '-'); // ndash/mdash -> -
  s = s.replace(/\u2026/g, '...');      // ellipsis

  // Replace literal unescaped backslashes that might break JSON (turn single \ into \\)
  // But avoid double-escaping existing escape sequences like \\n (two chars). We'll do a safe replace:
  s = s.replace(/(^|[^\\])\\(?![ntr"\\\/bfnu])/g, function(m, p1) { return p1 + '\\\\'; });

  // Convert any raw control chars (0x00 - 0x1F) except newline/tab/carriage return
  s = s.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, function(ch) {
    const code = ch.charCodeAt(0);
    return '\\u' + ('000' + code.toString(16)).slice(-4);
  });

  return s;
}

// helper: safe JSON decode of an extracted quoted string content
function decodeQuotedStringContent(strContent) {
  // strContent is the inner content captured from "key": "INNER"
  // Build a quoted JSON string and let JSON.parse decode escapes
  try {
    return JSON.parse('"' + strContent.replace(/"/g, '\\"') + '"');
  } catch (e) {
    // fallback: return raw
    return strContent;
  }
}

// regex-safe extractor for keys if JSON.parse fails
function fallbackFieldExtract(candidate) {
  const out = { Hook: null, caption: null, hashtags: null };

  // pattern to capture string value allowing escaped quotes
  const re = /"Hook"\s*:\s*"((?:\\.|[^"\\])*)"/s;
  const m = candidate.match(re);
  if (m) out.Hook = decodeQuotedStringContent(m[1]);

  const re2 = /"caption"\s*:\s*"((?:\\.|[^"\\])*)"/s;
  const m2 = candidate.match(re2);
  if (m2) out.caption = decodeQuotedStringContent(m2[1]);

  const re3 = /"hashtags"\s*:\s*"((?:\\.|[^"\\])*)"/s;
  const m3 = candidate.match(re3);
  if (m3) out.hashtags = decodeQuotedStringContent(m3[1]);

  return out;
}

const results = [];

for (const item of items) {
  const rawText = findTextField(item.json) || findTextField(item);
  const candidateRaw = findJsonSubstring(rawText);

  if (!candidateRaw) {
    results.push({ json: { error: 'No JSON candidate found', rawText } });
    continue;
  }

  // First sanitize
  const sanitized = sanitizeCandidate(candidateRaw);

  // Try JSON.parse directly
  try {
    const parsed = JSON.parse(sanitized);
    results.push({
      json: {
        Hook: parsed.Hook || parsed.hook || null,
        caption: parsed.caption || null,
        hashtags: parsed.hashtags || parsed.hashtag || parsed.tags || null,
        _candidate: candidateRaw,
        _sanitized: sanitized
      }
    });
    continue;
  } catch (err) {
    // JSON.parse failed after sanitization — attempt fallback extraction per-field
    const fallback = fallbackFieldExtract(sanitized);

    // If fallback found at least one field, return that (helps when parsed JSON broken but fields intact)
    if (fallback.Hook || fallback.caption || fallback.hashtags) {
      results.push({
        json: {
          Hook: fallback.Hook,
          caption: fallback.caption,
          hashtags: fallback.hashtags,
          note: 'Used fallback regex extraction (JSON.parse failed)',
          parseError: err.message,
          _candidate: candidateRaw,
          _sanitized: sanitized
        }
      });
    } else {
      // Last-ditch: try replacing literal unescaped newline characters with escaped \\n and parse
      const escapeNL = sanitized.replace(/\n/g, '\\n');
      try {
        const parsed2 = JSON.parse(escapeNL);
        results.push({
          json: {
            Hook: parsed2.Hook || null,
            caption: parsed2.caption || null,
            hashtags: parsed2.hashtags || null,
            _candidate: candidateRaw,
            _sanitized: escapeNL,
            note: 'Parsed after escaping literal newlines'
          }
        });
      } catch (err2) {
        // Give debugging info
        results.push({
          json: {
            error: 'JSON parse error (sanitizer fallback failed)',
            message: err.message,
            message2: err2 ? err2.message : null,
            candidate: candidateRaw,
            sanitized,
            rawText
          }
        });
      }
    }
  }
}

return results;

