// n8n Function node
// Input: items[*] — expects the assistant payload you showed
// Output: items with json containing No_of_images, AI_generated, images[]

function getAssistantText(item) {
  // try common path: item.json.output[0].content[0].text
  try {
    if (item.json && item.json.output && Array.isArray(item.json.output)) {
      for (const out of item.json.output) {
        if (out.content && Array.isArray(out.content)) {
          for (const c of out.content) {
            if (typeof c.text === 'string') return c.text;
          }
        }
        if (typeof out.text === 'string') return out.text;
      }
    }
  } catch (e) {}
  // fallback: any string field
  for (const k of Object.keys(item.json || {})) {
    if (typeof item.json[k] === 'string' && item.json[k].trim().startsWith('{')) return item.json[k];
  }
  return null;
}

function stripFences(s) {
  if (!s) return s;
  return s.replace(/```json|```/gi, '').replace(/`/g, '').trim();
}

function findJsonSubstring(s) {
  if (!s) return null;
  const start = s.indexOf('{');
  if (start === -1) return null;
  // simple stack to find matching }
  let stack = 0;
  for (let i = start; i < s.length; i++) {
    if (s[i] === '{') stack++;
    else if (s[i] === '}') {
      stack--;
      if (stack === 0) return s.slice(start, i + 1);
    }
  }
  return null;
}

// Main
const outputs = [];

for (const item of items) {
  const raw = getAssistantText(item);
  if (!raw) {
    outputs.push({ json: { error: 'assistant text not found', raw: item.json } });
    continue;
  }

  const cleaned = stripFences(raw);
  const candidate = findJsonSubstring(cleaned) || cleaned;

  // Replace literal CR/LF with escaped \n only if they are unescaped inside quotes
  // but for this payload we can try direct parse first
  try {
    const parsed = JSON.parse(candidate);
    // Ensure overlay_text uses real newlines instead of escaped \n if needed
    const images = Array.isArray(parsed.images) ? parsed.images.map(img => ({
      index: img.index != null ? img.index : null,
      overlay_text: typeof img.overlay_text === 'string' ? img.overlay_text : (img.overlayText || null)
    })) : [];

    outputs.push({
      json: {
        No_of_images: parsed.No_of_images != null ? parsed.No_of_images : images.length,
        AI_generated: typeof parsed.AI_generated === 'boolean' ? parsed.AI_generated : null,
        images,
        _raw_candidate: candidate
      }
    });
  } catch (err) {
    // Try a tolerant fallback: unescape literal \\n → \n and parse
    try {
      const candidateEscapedNL = candidate.replace(/\\n/g, '\\n'); // no-op but keep explicit
      const parsed2 = JSON.parse(candidateEscapedNL);
      const images = Array.isArray(parsed2.images) ? parsed2.images.map(img => ({
        index: img.index != null ? img.index : null,
        overlay_text: typeof img.overlay_text === 'string' ? img.overlay_text : (img.overlayText || null)
      })) : [];
      outputs.push({
        json: {
          No_of_images: parsed2.No_of_images != null ? parsed2.No_of_images : images.length,
          AI_generated: typeof parsed2.AI_generated === 'boolean' ? parsed2.AI_generated : null,
          images,
          _raw_candidate: candidateEscapedNL,
          note: 'Parsed after minor fallback'
        }
      });
    } catch (err2) {
      // Final fallback: regex-extract fields
      const fallback = { No_of_images: null, AI_generated: null, images: [] };
      const mNum = candidate.match(/"No_of_images"\s*:\s*(\d+)/i);
      if (mNum) fallback.No_of_images = parseInt(mNum[1], 10);
      const mBool = candidate.match(/"AI_generated"\s*:\s*(true|false)/i);
      if (mBool) fallback.AI_generated = mBool[1].toLowerCase() === 'true';
      // overlay_text occurrences
      const reOverlay = /"overlay_text"\s*:\s*"((?:\\.|[^"\\])*)"/g;
      let mm; let idx = 1;
      while ((mm = reOverlay.exec(candidate)) !== null) {
        // decode simple escapes
        const val = mm[1].replace(/\\"/g, '"').replace(/\\n/g, '\n');
        fallback.images.push({ index: idx++, overlay_text: val });
      }
      outputs.push({ json: { ...fallback, _raw_candidate: candidate, parse_error: err.message }});
    }
  }
}

return outputs;

