// 1. Safely extract the assistant JSON text
let raw = null;

// Try typical OpenAI → n8n structure
try {
  raw = items[0].json.output[0].content[0].text;
} catch (e) {}

// Fallback search
if (!raw) {
  for (const key of Object.keys(items[0].json)) {
    if (typeof items[0].json[key] === "string" && items[0].json[key].trim().startsWith("{")) {
      raw = items[0].json[key];
      break;
    }
  }
}

// If still nothing → return an error
if (!raw) {
  return [{ json: { error: "Could not find JSON text in input", input: items[0].json }}];
}

// Remove code fences if present
raw = raw.replace(/```json|```/g, "").trim();

// 2. Parse JSON
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (err) {
  return [{ json: { error: "JSON parse failed", message: err.message, raw }}];
}

// 3. Return clean structure
return [{
  json: {
    prompts: parsed.prompts || [],
    No_of_images: parsed.prompts ? parsed.prompts.length : 0
  }
}];
